import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { Search, ShoppingCart, Menu, X, User, Heart, Home, ChevronDown, ChevronUp, ArrowLeft } from 'lucide-react';
import { useCart } from '../../hooks/usecart';
import { useWishlist } from '../../hooks/useWishlist';

const Navbar = () => {
  const [isSearchActive, setIsSearchActive] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [activeMobileCat, setActiveMobileCat] = useState(null);

  // ==========================================
  // SCROLL STATE FOR GLASS EFFECT
  // ==========================================
  const [isScrolled, setIsScrolled] = useState(false);

  const desktopSearchInputRef = useRef(null);
  const mobileSearchInputRef = useRef(null);
  const navigate = useNavigate();
  const location = useLocation();

  // ==========================================
  // LIVE STORE CONNECTIONS
  // ==========================================
  const { items: cartItems = [] } = useCart();
  const cartCount = cartItems.reduce((total, item) => total + (Number(item.quantity) || 1), 0);

  const wishlist = useWishlist() || {};
  const wishlistItems = wishlist.items || [];
  const wishlistCount = wishlistItems.length;

  const navCategories = ['LIVING ROOM', 'BEDROOM', 'DINING', 'STUDY'];

  const megaMenuData = {
    'LIVING ROOM': [
      { title: 'Sofas', links: ['Fabric Sofas', 'Wooden Sofas', 'L-Shaped Sofas', 'Sofa Cum Beds', 'Recliners'] },
      { title: 'Seating', links: ['Lounge Chairs', 'Accent Chairs', 'Wing Chairs', 'Benches', 'Pouffes'] },
      { title: 'Tables', links: ['Coffee Tables', 'Side Tables', 'Console Tables', 'End Tables'] },
      { title: 'Storage', links: ['TV Units', 'Bookshelves', 'Display Units', 'Shoe Racks'] }
    ],
    'BEDROOM': [
      { title: 'Beds', links: ['Solid Wood Beds', 'Upholstered Beds', 'Beds with Storage', 'King Size Beds', 'Queen Size Beds'] },
      { title: 'Storage', links: ['Wardrobes', 'Chest of Drawers', 'Bedside Tables', 'Dressers'] },
      { title: 'Mattresses', links: ['Memory Foam', 'Orthopedic', 'Dual Comfort', 'Coir Mattresses'] }
    ],
    'DINING': [
      { title: 'Dining Sets', links: ['4 Seater Dining Sets', '6 Seater Dining Sets', '8 Seater Dining Sets', 'Extendable Dining'] },
      { title: 'Dining Storage', links: ['Crockery Units', 'Kitchen Cabinets', 'Sideboards'] },
      { title: 'Dining Decor', links: ['Table Linens', 'Coasters', 'Dining Serveware'] }
    ],
    'STUDY': [
      { title: 'Study Tables', links: ['Solid Wood Tables', 'Computer Tables', 'Foldable Tables'] },
      { title: 'Office Chairs', links: ['Ergonomic Chairs', 'Executive Chairs', 'Study Chairs'] },
      { title: 'Office Storage', links: ['File Cabinets', 'Office Bookcases', 'Wall Shelves'] }
    ]
  };

  // Detect scroll to trigger glass effect
  useEffect(() => {
    const handleScroll = () => {
      if (window.scrollY > 20) {
        setIsScrolled(true);
      } else {
        setIsScrolled(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setIsSearchActive(false);
    setIsMenuOpen(false);
    setActiveMobileCat(null);
  }, [location.pathname]);

  const handleDesktopSearchSubmit = (e) => {
    e.preventDefault();
    if (desktopSearchInputRef.current?.value.trim()) {
      navigate(`/products?search=${encodeURIComponent(desktopSearchInputRef.current.value)}`);
      desktopSearchInputRef.current.value = '';
    }
  };

  const handleMobileSearchSubmit = (e) => {
    e.preventDefault();
    if (mobileSearchInputRef.current?.value.trim()) {
      navigate(`/products?search=${encodeURIComponent(mobileSearchInputRef.current.value)}`);
      setIsSearchActive(false);
      mobileSearchInputRef.current.value = '';
    }
  };

  const toggleMobileSearch = () => {
    setIsSearchActive(!isSearchActive);
    if (!isSearchActive) {
      setTimeout(() => { mobileSearchInputRef.current?.focus(); }, 150);
    }
  };

  const toggleMobileCategory = (category) => {
    setActiveMobileCat(activeMobileCat === category ? null : category);
  };

  // =========================================================================
  // 🚀 CUSTOM CHECKOUT HEADER 
  // Renders only on /cart or /checkout routes
  // =========================================================================
  if (location.pathname === '/cart' || location.pathname === '/checkout') {
    return (
      <header className={`w-full sticky top-0 z-50 border-b border-gray-200 transition-all duration-300 ${isScrolled ? 'bg-white/75 backdrop-blur-lg shadow-md' : 'bg-white shadow-sm'
        }`}>
        {/* CHANGED py-4 md:py-5 to py-3 to exactly reuse standard navbar height */}
        <div className="container mx-auto px-4 py-3 relative flex items-center justify-between">

          {/* Left: Back Arrow & Logo */}
          <div className="flex items-center gap-4 h-10">
            <button
              onClick={() => navigate(-1)}
              className="text-gray-500 hover:text-orange-500 transition-colors outline-none focus:outline-none flex items-center justify-center h-full"
              title="Go Back"
            >
              <ArrowLeft size={28} strokeWidth={1.5} />
            </button>
            <Link to="/" className="flex items-center gap-2 outline-none focus:outline-none">
              <img
                src="https://i.postimg.cc/q7hqkqwB/568094498-17843891301597329-6427631544708793099-n.jpg"
                alt="Logo"
                className="h-8 w-8 md:h-10 md:w-10 object-cover rounded-md hidden sm:block"
              />
              <h1 className="text-xl md:text-2xl font-black tracking-tight text-gray-900">
                Videm's <span className="text-orange-500">Gallery</span>
              </h1>
            </Link>
          </div>

          {/* Center: Progress Tracker (Hidden on small mobile) */}
          <div className="hidden md:flex items-center justify-center flex-1 max-w-lg mx-8 h-10">
            <div className={`text-lg font-medium ${location.pathname === '/cart' ? 'text-orange-500 font-semibold' : 'text-gray-500'}`}>Cart</div>
            <div className="flex-1 border-t border-dashed border-gray-300 mx-3 mt-1"></div>
            <div className={`text-lg font-medium ${location.pathname === '/checkout' ? 'text-orange-500 font-semibold' : 'text-gray-800'}`}>Address</div>
            <div className="flex-1 border-t border-dashed border-gray-300 mx-3 mt-1"></div>
            <div className="text-lg font-medium text-gray-800">Payment</div>
          </div>

          {/* Right: Support Contact (Hidden on mobile) */}
          <div className="hidden lg:flex flex-col text-right justify-center h-10">
            <span className="text-sm text-gray-600 tracking-wide leading-tight">Have Questions? We're Here To Help</span>
            <span className="text-base text-orange-500 font-bold tracking-wide leading-tight">Call : +91-9314444747</span>
          </div>

        </div>
      </header>
    );
  }

  // =========================================================================
  // STANDARD NAVBAR (Renders on all other pages)
  // =========================================================================
  return (
    <>
      <header className={`w-full sticky top-0 z-50 transition-all duration-300 ${isScrolled ? 'bg-white/80 backdrop-blur-lg shadow-md' : 'bg-white shadow-sm'
        }`}>

        {/* Top Promotional Banner */}
        <div className={`w-full py-1.5 border-b border-gray-200 transition-colors duration-300 ${isScrolled ? 'bg-transparent' : 'bg-gray-50'
          }`}>
          <p className="text-center text-xs md:text-sm text-gray-700">
            Free Shipping on Orders Above ₹10,000 | <span className="text-orange-500 font-semibold">Use Code: VIDEM10</span>
          </p>
        </div>

        {/* Main Navbar Header */}
        <div className="container mx-auto px-4 py-3 relative flex items-center justify-between">

          {/* Mobile Hamburger Menu Button */}
          <button
            className="md:hidden p-1 z-20 text-gray-700 hover:text-orange-500 transition-colors outline-none focus:outline-none focus:ring-0"
            onClick={() => setIsMenuOpen(true)}
          >
            <Menu size={26} />
          </button>

          {/* Brand Name with Logo */}
          <Link to="/" className="group absolute left-1/2 -translate-x-1/2 md:static md:translate-x-0 z-10 flex items-center gap-2">
            <img
              src="https://i.postimg.cc/q7hqkqwB/568094498-17843891301597329-6427631544708793099-n.jpg"
              alt="Videm's Gallery Logo"
              className="h-8 w-8 md:h-10 md:w-10 object-cover rounded-md"
            />
            <h1 className="text-xl md:text-2xl font-bold tracking-tight whitespace-nowrap">
              <span className="text-gray-900 group-hover:text-orange-500 transition-colors duration-300">Videm's</span>{' '}
              <span className="text-orange-500 group-hover:text-gray-900 transition-colors duration-300">Gallery</span>
            </h1>
          </Link>

          {/* DESKTOP Permanent Search Bar */}
          <form onSubmit={handleDesktopSearchSubmit} className="hidden md:flex flex-1 max-w-2xl mx-8 h-10">
            <input
              ref={desktopSearchInputRef}
              type="text"
              placeholder="Search for furniture and more..."
              className="flex-1 h-full bg-gray-100 text-sm text-gray-800 outline-none rounded-l-md px-4 focus:ring-1 focus:ring-orange-500 transition-all"
            />
            <button type="submit" className="h-10 w-12 flex-shrink-0 flex items-center justify-center bg-orange-500 text-white rounded-r-md hover:bg-orange-600 transition-colors outline-none focus:outline-none">
              <Search size={20} />
            </button>
          </form>

          {/* Right Side Navigation Icons */}
          <div className="flex items-center gap-3 z-20">
            {/* MOBILE Icons */}
            <div className="flex md:hidden items-center gap-4">
              <button onClick={toggleMobileSearch} className="h-9 w-9 flex items-center justify-center bg-orange-500 text-white rounded-md transition-colors shadow-sm outline-none focus:outline-none focus:ring-0">
                <Search size={18} />
              </button>
              <Link to="/login" className="p-1 text-gray-700 hover:text-orange-500 transition-colors outline-none focus:outline-none">
                <User size={24} />
              </Link>
            </div>

            {/* DESKTOP Icons */}
            <div className="hidden md:flex items-center space-x-6 lg:space-x-8 flex-shrink-0 h-10">
              <Link to="/login" className="flex flex-col items-center justify-center gap-1 text-gray-700 hover:text-orange-500 transition-colors outline-none focus:outline-none h-full">
                <User size={24} />
                <span className="text-[10px] font-bold tracking-wider uppercase">Profile</span>
              </Link>

              <Link to="/wishlist" className="flex flex-col items-center justify-center gap-1 text-gray-700 hover:text-orange-500 transition-colors relative outline-none focus:outline-none h-full">
                <div className="relative">
                  <Heart size={24} />
                  {wishlistCount > 0 && (
                    <span className="absolute -top-2 -right-2 bg-red-500 text-white text-[10px] font-bold h-5 w-5 rounded-full flex items-center justify-center border border-white">
                      {wishlistCount > 99 ? '99+' : wishlistCount}
                    </span>
                  )}
                </div>
                <span className="text-[10px] font-bold tracking-wider uppercase">Wishlist</span>
              </Link>

              <Link to="/cart" className="flex flex-col items-center justify-center gap-1 text-gray-700 hover:text-orange-500 transition-colors relative outline-none focus:outline-none h-full">
                <div className="relative">
                  <ShoppingCart size={24} />
                  {cartCount > 0 && (
                    <span className="absolute -top-2 -right-2 bg-orange-500 text-white text-[10px] font-bold h-5 w-5 rounded-full flex items-center justify-center border border-white">
                      {cartCount > 99 ? '99+' : cartCount}
                    </span>
                  )}
                </div>
                <span className="text-[10px] font-bold tracking-wider uppercase">Cart</span>
              </Link>
            </div>
          </div>
        </div>

        {/* MOBILE Dropdown Search Bar */}
        <div className={`md:hidden absolute top-full left-0 w-full bg-white border-t border-gray-100 shadow-md p-3 transition-all duration-300 origin-top ${isSearchActive ? 'scale-y-100 opacity-100' : 'scale-y-0 opacity-0 pointer-events-none'}`}>
          <form onSubmit={handleMobileSearchSubmit} className="flex items-center h-10 w-full">
            <input
              ref={mobileSearchInputRef}
              type="text"
              placeholder="Search for furniture..."
              className="flex-1 h-full bg-gray-100 text-sm text-gray-800 outline-none rounded-l-md px-4 focus:ring-1 focus:ring-orange-500"
            />
            <button type="submit" className="h-10 w-12 flex-shrink-0 flex items-center justify-center bg-orange-500 text-white rounded-r-md hover:bg-orange-600 transition-colors outline-none focus:outline-none">
              <Search size={20} />
            </button>
          </form>
        </div>

        {/* Desktop Category Links with MEGA MENU */}
        <div className={`hidden md:block w-full border-t border-gray-100 relative transition-colors duration-300 ${isScrolled ? 'bg-transparent' : 'bg-white'
          }`}>
          <div className="container mx-auto px-4">
            <ul className="flex items-center justify-center space-x-12">
              {navCategories.map((category) => (
                <li key={category} className="group py-3">
                  <Link
                    to={`/products?category=${category.toLowerCase().replace(' ', '-')}`}
                    className="relative text-sm font-bold text-gray-800 group-hover:text-orange-500 tracking-wide transition-colors inline-block h-full outline-none focus:outline-none"
                  >
                    {category}
                    <span className="absolute -bottom-1.5 left-1/2 w-0 h-[2px] bg-orange-500 -translate-x-1/2 transition-all duration-300 ease-out group-hover:w-full"></span>
                  </Link>

                  {/* Mega Menu Dropdown Container */}
                  <div className="absolute left-0 top-full w-full bg-white shadow-xl border-t border-gray-100 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-300 z-50">
                    <div className="container mx-auto px-12 py-8 flex justify-start gap-16">
                      {megaMenuData[category]?.map((column) => (
                        <div key={column.title} className="flex flex-col min-w-[150px]">
                          <h3 className="text-gray-900 font-bold mb-4 uppercase text-sm tracking-wider border-b border-gray-200 pb-2">
                            {column.title}
                          </h3>
                          <ul className="space-y-3">
                            {column.links.map((link) => (
                              <li key={link}>
                                <Link
                                  to={`/products?search=${link.toLowerCase().replace(' ', '-')}`}
                                  className="text-gray-500 hover:text-orange-500 text-sm transition-colors block outline-none focus:outline-none"
                                >
                                  {link}
                                </Link>
                              </li>
                            ))}
                          </ul>
                        </div>
                      ))}
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          </div>
        </div>
      </header>

      {/* Mobile Sidebar Drawer */}
      {isMenuOpen && (
        <div className="fixed inset-0 bg-white z-50 md:hidden flex flex-col shadow-2xl">
          <div className="p-4 border-b border-gray-100 flex items-center justify-between sticky top-0 bg-white z-10">
            <button onClick={() => setIsMenuOpen(false)} className="text-gray-700 hover:text-orange-500 transition-colors outline-none focus:outline-none focus:ring-0">
              <X size={28} />
            </button>
            <div className="flex items-center gap-2 group cursor-pointer">
              <img
                src="https://i.postimg.cc/q7hqkqwB/568094498-17843891301597329-6427631544708793099-n.jpg"
                alt="Videm's Gallery Logo"
                className="h-7 w-7 object-cover rounded-md"
              />
              <h1 className="text-xl font-bold tracking-tight text-gray-900">
                <span className="text-gray-900 group-hover:text-orange-500 transition-colors duration-300">Videm's</span>{' '}
                <span className="text-orange-500 group-hover:text-gray-900 transition-colors duration-300">Gallery</span>
              </h1>
            </div>
            <div className="w-7"></div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 pb-24">
            {navCategories.map((mainCat) => (
              <div key={mainCat} className="border-b border-gray-100 last:border-none">
                <button
                  onClick={() => toggleMobileCategory(mainCat)}
                  className="w-full flex items-center justify-between py-4 text-left font-bold text-gray-900 text-base uppercase tracking-wide outline-none focus:outline-none focus:ring-0"
                  style={{ WebkitTapHighlightColor: 'transparent' }}
                >
                  <span>{mainCat}</span>
                  {activeMobileCat === mainCat ? <ChevronUp size={18} className="text-orange-500" /> : <ChevronDown size={18} />}
                </button>

                <div className={`transition-all duration-300 overflow-hidden ${activeMobileCat === mainCat ? 'max-h-[1000px] opacity-100 pb-4' : 'max-h-0 opacity-0'}`}>
                  <div className="space-y-4 pl-2">
                    {megaMenuData[mainCat]?.map((group) => (
                      <div key={group.title}>
                        <h3 className="text-sm font-bold text-orange-500 uppercase tracking-wide mb-2 mt-2">
                          {group.title}
                        </h3>
                        <ul className="space-y-2 pl-3 border-l-2 border-gray-100">
                          {group.links.map((link) => (
                            <li key={link}>
                              <Link
                                to={`/products?search=${link.toLowerCase().replace(' ', '-')}`}
                                onClick={() => setIsMenuOpen(false)}
                                className="group relative inline-block text-sm text-gray-600 hover:text-orange-500 transition-colors py-1 outline-none focus:outline-none"
                                style={{ WebkitTapHighlightColor: 'transparent' }}
                              >
                                {link}
                                <span className="absolute bottom-0 left-1/2 w-0 h-[1.5px] bg-orange-500 -translate-x-1/2 transition-all duration-300 ease-out group-hover:w-full"></span>
                              </Link>
                            </li>
                          ))}
                        </ul>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* MOBILE Bottom Navigation */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 z-40 pb-2 pt-2 px-2">
        <div className="flex items-center justify-around">
          <Link to="/" className="group relative flex flex-col items-center gap-1 text-gray-500 hover:text-orange-500 transition-colors w-16 py-1 outline-none focus:outline-none" style={{ WebkitTapHighlightColor: 'transparent' }}>
            <Home size={22} className="group-hover:-translate-y-0.5 transition-transform duration-300" />
            <span className="text-[10px] font-medium">Home</span>
            <span className="absolute bottom-0 left-1/2 w-0 h-[2px] bg-orange-500 -translate-x-1/2 transition-all duration-300 ease-out group-hover:w-1/2"></span>
          </Link>

          <button onClick={toggleMobileSearch} className="group relative flex flex-col items-center gap-1 text-gray-500 hover:text-orange-500 transition-colors w-16 py-1 outline-none focus:outline-none focus:ring-0" style={{ WebkitTapHighlightColor: 'transparent' }}>
            <Search size={22} className="group-hover:-translate-y-0.5 transition-transform duration-300" />
            <span className="text-[10px] font-medium">Search</span>
            <span className="absolute bottom-0 left-1/2 w-0 h-[2px] bg-orange-500 -translate-x-1/2 transition-all duration-300 ease-out group-hover:w-1/2"></span>
          </button>

          <Link to="/wishlist" className="group relative flex flex-col items-center gap-1 text-gray-500 hover:text-orange-500 transition-colors w-16 py-1 outline-none focus:outline-none" style={{ WebkitTapHighlightColor: 'transparent' }}>
            <div className="relative">
              <Heart size={22} className="group-hover:-translate-y-0.5 transition-transform duration-300" />
              {wishlistCount > 0 && (
                <span className="absolute -top-1 -right-2 bg-red-500 text-white text-[9px] font-bold h-4 w-4 rounded-full flex items-center justify-center">
                  {wishlistCount > 99 ? '99+' : wishlistCount}
                </span>
              )}
            </div>
            <span className="text-[10px] font-medium">Wishlist</span>
            <span className="absolute bottom-0 left-1/2 w-0 h-[2px] bg-orange-500 -translate-x-1/2 transition-all duration-300 ease-out group-hover:w-1/2"></span>
          </Link>

          <Link to="/cart" className="group relative flex flex-col items-center gap-1 text-gray-500 hover:text-orange-500 transition-colors w-16 py-1 outline-none focus:outline-none" style={{ WebkitTapHighlightColor: 'transparent' }}>
            <div className="relative">
              <ShoppingCart size={22} className="group-hover:-translate-y-0.5 transition-transform duration-300" />
              {cartCount > 0 && (
                <span className="absolute -top-1 -right-2 bg-orange-500 text-white text-[10px] font-bold h-4 w-4 rounded-full flex items-center justify-center border border-white">
                  {cartCount > 99 ? '99+' : cartCount}
                </span>
              )}
            </div>
            <span className="text-[10px] font-medium">Cart</span>
            <span className="absolute bottom-0 left-1/2 w-0 h-[2px] bg-orange-500 -translate-x-1/2 transition-all duration-300 ease-out group-hover:w-1/2"></span>
          </Link>
        </div>
      </div>
    </>
  );
};

export default Navbar;
